// File Validation with Enhanced Error Handling
const items = $input.all();
const validatedItems = [];

for (const item of items) {
  try {
    console.log(item)
    const binary = item.binary;

    // Check if file exists
    if (!binary || !binary['Upload_PDF_File']) {
      throw new Error('No file uploaded. Please select a PDF file.');
    }

    const file = binary['Upload_PDF_File'];

    // Validate MIME type
    const validTypes = ['application/pdf'];
    if (!validTypes.includes(file.mimeType)) {
      throw new Error(`Invalid file type: ${file.mimeType}. Only PDF files are accepted.`);
    }

    // Validate file size (max 50MB)
    const maxSize = 50 * 1024 * 1024;
    const fileSize = Buffer.byteLength(file.data, 'base64');

    if (fileSize > maxSize) {
      const sizeMB = (fileSize / 1024 / 1024).toFixed(2);
      throw new Error(`File too large: ${sizeMB} MB. Maximum allowed size is 50MB.`);
    }
    // Validate file is not empty
    if (fileSize <= 0) {
      throw new Error('File appears to be empty or corrupted.');
    }

    // Add metadata
    item.json.fileSize = fileSize;
    item.json.fileSizeMB = (fileSize / 1024 / 1024).toFixed(2);
    item.json.fileName = file.fileName || 'uploaded.pdf';
    item.json.uploadTime = new Date().toISOString();
    item.json.validationStatus = 'passed';
    item.json.outputFormat = item.json['Output Format'] || 'Both (TXT + CSV)';

    // Normalize binary data field name
    item.binary.data = file;

    validatedItems.push(item);

  } catch (error) {
    // Return error in standardized format
    console.log(error)
    return [{
      json: {
        success: false,
        error: error.message,
        validationStatus: 'failed',
        timestamp: new Date().toISOString()
      }
    }];
  }
}

return validatedItems;

// PDF Type Detection (Text-based vs Scanned) - FIXED for Binary Data Preservation
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    console.log(item)
    // CRITICAL FIX: Ensure binary data exists and is accessible
    if (!item.binary || !item.binary.Upload_PDF_File) {
      throw new Error('No binary data found in item');
    }

    const binary = item.binary.Upload_PDF_File;
    const pdfBuffer = Buffer.from(binary.data, 'base64');

    // Convert buffer to string for analysis
    const pdfString = pdfBuffer.toString('latin1');
    console.log(pdfString)
    // Detection heuristics
    const hasTextContent = (
      pdfString.includes('/ToUnicode') || 
      pdfString.includes('/Encoding') ||
      pdfString.includes('/Font') ||
      (pdfString.match(/\(.*\)/g) || []).length > 50
    );
    console.log(hasTextContent)

    const hasImages = (
      pdfString.includes('/Image') || 
      pdfString.includes('/XObject') ||
      pdfString.includes('/DCTDecode') ||
      pdfString.includes('/FlateDecode')
    );

    // Count approximate text content
    const textMatches = pdfString.match(/\([^)]{10,}\)/g) || [];
    const textContentScore = textMatches.length;

    // Determine PDF type
    let pdfType = 'text-based';
    let confidence = 'low';

    if (textContentScore > 100 && hasTextContent) {
      pdfType = 'text-based';
      confidence = 'high';
    } else if (textContentScore > 20 && hasTextContent) {
      pdfType = 'mixed';
      confidence = 'medium';
    } else if (hasImages) {
      pdfType = 'scanned';
      confidence = 'medium';
    }

    // Add detection results to item
    item.json.pdfType = pdfType;
    item.json.detectionConfidence = confidence;
    item.json.textContentScore = textContentScore;
    item.json.hasImages = hasImages;
    item.json.hasTextContent = hasTextContent;
    item.json.detectionMethod = 'content-analysis';
    item.json.detectionTime = new Date().toISOString();

    // CRITICAL: Preserve binary data by keeping it in the item
    // The binary.data field is already set by File Validation, just keep it

    results.push(item);

  } catch (error) {
    // Fallback: assume text-based if detection fails
    item.json.pdfType = 'text-based';
    item.json.detectionConfidence = 'low';
    item.json.detectionError = error.message;

    // CRITICAL: Even on error, preserve binary data if it exists
    // Don't modify item.binary to avoid losing the data

    results.push(item);
  }
}

return results;

