// Text Cleanup and Processing
const items = $input.all();
const results = [];

for (const item of items) {
  console.log(item)
  let text = item.json.data || item.json.extractedText || item.json.text || '';
  const outputFormat =  $('PDF Type Detection1').first().json.outputFormat;

  console.log(text)
    item.json.outputFormat = outputFormat;
    item.json.fileName = $('File Validation1').first().json.fileName;

  // Skip if no text extracted
  if (!text || text.trim().length === 0) {
    item.json.cleanedText = '';
    item.json.processingError = 'No text could be extracted from PDF';
    item.json.wordCount = 0;
    item.json.characterCount = 0;
    results.push(item);
    continue;
  }

  // Cleanup operations
  // 1. Normalize line breaks
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // 2. Remove excessive whitespace
  text = text.replace(/[ \t]+/g, ' ');

  // 3. Remove multiple consecutive line breaks (keep max 2)
  text = text.replace(/\n{3,}/g, '\n\n');

  // 4. Trim each line
  text = text.split('\n').map(line => line.trim()).join('\n');

  // 5. Remove zero-width characters
  text = text.replace(/[\u200B-\u200D\uFEFF]/g, '');

  // 6. Fix common OCR errors (optional)
  const ocrCorrections = {
    '0O': 'OO',  // Zero followed by O
    'O0': 'O0',  // O followed by zero
    'l1': 'l1',  // lowercase L and 1
  };

  // Calculate statistics
  const wordCount = text.split(/\s+/).filter(w => w.length > 0).length;
  const characterCount = text.length;
  const lineCount = text.split('\n').filter(l => l.length > 0).length;

  // Detect if text contains structured data
  const hasTabular = /\t/.test(text) || /\s{3,}/.test(text);
  const hasNumberedLists = /^\d+[\.\)]\s/m.test(text);
  const hasBulletPoints = /^[•\-\*]\s/m.test(text);


  // Store results
  item.json.cleanedText = text.trim();
  item.json.originalText = item.json.data || item.json.extractedText;
  item.json.wordCount = wordCount;
  item.json.characterCount = characterCount;
  item.json.lineCount = lineCount;
  item.json.hasTabularData = hasTabular;
  item.json.hasNumberedLists = hasNumberedLists;
  item.json.hasBulletPoints = hasBulletPoints;
  item.json.processingStatus = 'success';
  item.json.processingTime = new Date().toISOString();

  results.push(item);
}

return results;

