const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.cleanedText || '';

  if (!text) {
    item.json.txtError = 'No text available to create TXT file';
    results.push(item);
    continue;
  }

  // Add header information
  const header = `========================================
Extracted from: ${item.json.fileName}
Extraction Date: ${new Date().toISOString()}
Word Count: ${item.json.wordCount}
Character Count: ${item.json.characterCount}
========================================\n\n`;

  const fullText = header + text;

  // Create TXT binary
  const txtBuffer = Buffer.from(fullText, 'utf-8');
  const txtBase64 = txtBuffer.toString('base64');

  const txtFileName = item.json.fileName.replace('.pdf', '') + '_extracted.txt';

  item.binary.txtFile = {
    data: txtBase64,
    mimeType: 'text/plain',
    fileName: txtFileName,
    fileExtension: 'txt',
    fileSize: txtBuffer.length
  };

  item.json.txtFileName = txtFileName;
  item.json.txtFileSize = txtBuffer.length;
  item.json.txtCreated = true;

  results.push(item);
}

return results;

// Create CSV File with Table Detection
const items = $input.all();
