function detectAndParseTables(text) {
  const lines = text.split('\n').filter(line => line.trim());
  const tables = [];
  let currentTable = [];
  let inTable = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Heuristics for table detection
    const hasMultipleSpaces = /\s{3,}/.test(line);
    const hasTabs = /\t/.test(line);
    const hasMultipleColumns = line.split(/\t+|\s{3,}/).length >= 2;

    // Check if line looks like a table row
    const isTableRow = (hasMultipleSpaces || hasTabs) && hasMultipleColumns;

    if (isTableRow) {
      if (!inTable) {
        inTable = true;
        currentTable = [];
      }
      currentTable.push(line);
    } else {
      // End of table
      if (inTable && currentTable.length >= 2) {
        tables.push([...currentTable]);
      }
      inTable = false;
      currentTable = [];
    }
  }

  // Add last table if exists
  if (currentTable.length >= 2) {
    tables.push(currentTable);
  }

  return tables;
}

function tableToCSV(table) {
  const csvRows = [];

  for (const row of table) {
    // Split by tabs or multiple spaces
    const columns = row
      .split(/\t+|\s{3,}/)
      .map(col => col.trim())
      .filter(col => col.length > 0);

    // Escape and quote columns
    const escapedColumns = columns.map(col => {
      // Escape quotes
      col = col.replace(/"/g, '""');

      // Quote if contains comma, quote, or newline
      if (col.includes(',') || col.includes('"') || col.includes('\n')) {
        return `"${col}"`;
      }

      // Quote if starts/ends with space
      if (col.startsWith(' ') || col.endsWith(' ')) {
        return `"${col}"`;
      }

      return col;
    });

    csvRows.push(escapedColumns.join(','));
  }

  return csvRows.join('\n');
}

function textToSingleColumnCSV(text) {
  const lines = text.split('\n').filter(line => line.trim());

  const csvLines = ['Line Number,Content'];

  lines.forEach((line, index) => {
    const escaped = line.replace(/"/g, '""');
    csvLines.push(`${index + 1},"${escaped}"`);
  });

  return csvLines.join('\n');
}

for (const item of items) {
  const text = item.json.cleanedText || '';

  if (!text) {
    item.json.csvError = 'No text available to create CSV file';
    results.push(item);
    continue;
  }

  let csvContent = '';
  let conversionMethod = '';

  // Try to detect tables
  const tables = detectAndParseTables(text);

  if (tables.length > 0) {
    // Found table(s) - convert first table
    csvContent = tableToCSV(tables[0]);
    conversionMethod = 'table-detection';
    item.json.tablesDetected = tables.length;

    // If multiple tables, note in metadata
    if (tables.length > 1) {
      item.json.additionalTables = tables.length - 1;
      item.json.note = `${tables.length} tables detected. Only first table converted to CSV.`;
    }
  } else {
    // No tables found - convert to single column CSV
    csvContent = textToSingleColumnCSV(text);
    conversionMethod = 'line-by-line';
    item.json.tablesDetected = 0;
  }

  // Create CSV binary
  const csvBuffer = Buffer.from(csvContent, 'utf-8');
  const csvBase64 = csvBuffer.toString('base64');
  console.log(item, item.json)
  const csvFileName = item.json.fileName.replace('.pdf', '') + '_extracted.csv';

  item.binary.csvFile = {
    data: csvBase64,
    mimeType: 'text/csv',
    fileName: csvFileName,
    fileExtension: 'csv',
    fileSize: csvBuffer.length
  };

  item.json.csvFileName = csvFileName;
  item.json.csvFileSize = csvBuffer.length;
  item.json.csvCreated = true;
  item.json.csvConversionMethod = conversionMethod;
  item.json.csvRowCount = csvContent.split('\n').length;

  results.push(item);
}

return results;

// Prepare Final Response with Download Links
const items = $input.all();
const results = [];

for (const item of items) {
  const response = {
    success: true,
    message: 'PDF processed successfully',
    processingDetails: {
      originalFile: item.json.fileName,
      fileSize: `${item.json.fileSizeMB} MB`,
      pdfType: item.json.pdfType,
      detectionConfidence: item.json.detectionConfidence,
      uploadTime: item.json.uploadTime,
      processingTime: item.json.processingTime
    },
    extractionStats: {
      wordCount: item.json.wordCount,
      characterCount: item.json.characterCount,
      lineCount: item.json.lineCount,
      hasTabularData: item.json.hasTabularData
    },
    outputFiles: []
  };

  // Add TXT file info
  if (item.json.txtCreated && item.binary.txtFile) {
    response.outputFiles.push({
      format: 'TXT',
      fileName: item.json.txtFileName,
      fileSize: `${(item.json.txtFileSize / 1024).toFixed(2)} KB`,
      mimeType: 'text/plain'
    });
  }

  // Add CSV file info
  if (item.json.csvCreated && item.binary.csvFile) {
    response.outputFiles.push({
      format: 'CSV',
      fileName: item.json.csvFileName,
      fileSize: `${(item.json.csvFileSize / 1024).toFixed(2)} KB`,
      mimeType: 'text/csv',
      conversionMethod: item.json.csvConversionMethod,
      tablesDetected: item.json.tablesDetected,
      rowCount: item.json.csvRowCount
    });
  }

  // Add warnings if any
  if (item.json.requiresOCR) {
    response.warnings = [
      'Scanned PDF detected. Text extraction may be incomplete.',
      'Consider using OCR service for better results.'
    ];
  }

  if (item.json.processingError) {
    response.warnings = response.warnings || [];
    response.warnings.push(item.json.processingError);
  }

  // Keep binary files for download
  const newItem = {
    json: response,
    binary: {}
  };

  if (item.binary.txtFile) {
    newItem.binary.txtFile = item.binary.txtFile;
  }

  if (item.binary.csvFile) {
    newItem.binary.csvFile = item.binary.csvFile;
  }

  results.push(newItem);
}

return results;
